/** 渠道站点相关方法 */
import {
  DEFAULT_LINEAR_UNIT,
  DEFAULT_PLATFORM_CODE,
  DEFAULT_PLATFORM_REGION_CODE,
  DEFAULT_SITE_TENANT_CODE,
  DEFAULT_SITE_TENANT_CURRENCY_SYMBOL,
  DEFAULT_TIMEZONE,
  DEFAULT_WEIGHT_UNIT,
  INCH_TO_CM,
  KG_TO_LB,
  PLATFORM_ENUM,
  PLATFORM_REGION_ENUM,
  SPT_PLATFORM_CODE,
  SPT_PLATFORM_REGION_CODE,
  SPT_SITE_TENANT_CODE,
  SPT_SITE_TENANT_CURRENCY_CODE,
  SPT_SITE_TENANT_CURRENCY_SYMBOL,
  SPT_SITE_TENANT_LINEAR_UNIT_CODE,
  SPT_SITE_TENANT_TIMEZONE,
  SPT_SITE_TENANT_WEIGHT_UNIT_CODE,
  SPT_UNIT_TRANSFORM_CONFIG,
  USD,
} from '../const';
import { localCache } from './localCache';
import Big from 'big.js';

/**
 * 获取当前渠道站点
 */
export function getSiteTenantCode(): string {
  return localCache.get(SPT_SITE_TENANT_CODE) || DEFAULT_SITE_TENANT_CODE;
}

/**
 * 获取当前渠道
 */
export function getCurrentPlatformCode(): string {
  return localCache.get(SPT_PLATFORM_CODE) || DEFAULT_PLATFORM_CODE;
}

/**
 * 获取当前站点
 */
export function getCurrentPlatformRegionCode(): string {
  return localCache.get(SPT_PLATFORM_REGION_CODE) || DEFAULT_PLATFORM_REGION_CODE;
}

/**
 * 获取当前渠道站点货币符号
 */
export function getSiteTenantCurrencySymbol(): string {
  return localCache.get(SPT_SITE_TENANT_CURRENCY_SYMBOL) || DEFAULT_SITE_TENANT_CURRENCY_SYMBOL;
}

/**
 * 获取当前渠道站点货币编码
 */
export function getSiteTenantCurrencyCode(): string {
  return localCache.get(SPT_SITE_TENANT_CURRENCY_CODE) || USD;
}

/**
 * 获取当前渠道站点时区
 */
export function getSiteTenantTimeZone(): string {
  return localCache.get(SPT_SITE_TENANT_TIMEZONE) || DEFAULT_TIMEZONE;
}

/**
 * 获取当前渠道站点长度单位
 */
export function getSiteTenantLinearUnit(): string {
  return localCache.get(SPT_SITE_TENANT_LINEAR_UNIT_CODE) || DEFAULT_LINEAR_UNIT;
}

/**
 * 获取当前渠道站点重量单位
 */
export function getSiteTenantWeightUnit(): string {
  return localCache.get(SPT_SITE_TENANT_WEIGHT_UNIT_CODE) || DEFAULT_WEIGHT_UNIT;
}

/**
 * 校验当前站点逻辑返回布尔值
 */
type PlatformRegionMap = {
  [key in PLATFORM_REGION_ENUM]?: boolean;
};
type PlatformMap = {
  [key in PLATFORM_ENUM]?: PlatformRegionMap;
};

// 判断多渠道，根据传入的渠道配置,返回布尔值,默认false,提供默认布尔值可以选择自定义填入
export const checkMultiChannel = (checkObject: PlatformMap, defaultBoolean?: boolean) => {
  // 获取当前站点
  const [platformRegion, platform] = getSiteTenantCode()?.split('_');
  // 返回当前站点的配置值
  return checkObject?.[platform as PLATFORM_ENUM]?.[platformRegion as PLATFORM_REGION_ENUM] || defaultBoolean || false;
};

interface TransformLinearParams {
  originalValue: string|number // 原始值
  originalUnit: string; // 原始单位
  expectUnit: string; // 期望的单位
  decimal?: number; // 保留小数位数
}

interface TransformConfig {
  from: string;
  to: string;
  value: number;
}
/**
 * @description: 根据配置文件转化单位
 * @param { string|number } originalValue 原始值,string类型或者number类型的数字
 * @param { string } originalUnit 原始单位
 * @param { string } expectUnit 期望的单位
 * @param { number } decimal 保留小数位数, 默认为2
 * @returns { number|string } 转换后的数值，以string为主
*/
export const transformUnit = ({ originalUnit, originalValue, expectUnit, decimal = 2 }: TransformLinearParams) => {
  if (originalUnit === expectUnit) return originalValue;
  try {
    // 从localStorage中获取单位转换配置
    const transformConfig = (localCache.get(SPT_UNIT_TRANSFORM_CONFIG) || []) as TransformConfig[];

    if (!transformConfig.length) return originalValue;
    // 查找对应的单位转化进制数据
    const targetConfig = transformConfig.find((item) => item.from === originalUnit && item.to === expectUnit);

    if (!targetConfig) return originalValue;

    return new Big(originalValue).mul(targetConfig.value).toFixed(decimal);
  } catch (error) {
    console.error(error);
    return originalValue;
  }
}
